   130→        if (content) {
   131→          if (Array.isArray(content)) {
   132→            content.forEach(block => {
   133→              if (block.type === 'text' && block.text) {
   134→                result.formattedOutput += `${this.colors.cyan}${block.text}${this.colors.reset}\n`;
   135→              }
   136→            });
   137→          } else {
   138→            result.formattedOutput = `${this.colors.cyan}${content}${this.colors.reset}`;
   139→          }
   140→        }
   141→        break;
   142→      }
   143→
   144→      case 'content_block_start': {
   145→        const blockType = data.content_block?.type;
   146→        if (blockType === 'tool_use') {
   147→          const toolName = data.content_block?.name || 'unknown';
   148→          result.actions.push({ action: 'start_spinner', toolName });
   149→          result.formattedOutput = `Starting tool: ${toolName}`;
   150→        }
   151→        break;
   152→      }
   153→
   154→      case 'content_block_delta': {
   155→        const deltaType = data.delta?.type;
   156→        if (deltaType === 'text_delta' && data.delta?.text) {
   157→          result.actions.push({ action: 'stop_spinner' });
   158→          result.formattedOutput = `${this.colors.cyan}${data.delta.text}${this.colors.reset}`;
   159→        }
   160→        break;
   161→      }
   162→
   163→      case 'tool_use': {
   164→        const toolName = data.name || 'unknown';
   165→        const input = data.input ? JSON.stringify(data.input) : '{}';
   166→        result.actions.push({ action: 'stop_spinner' });
   167→        result.actions.push({ action: 'start_spinner', toolName });
   168→        result.formattedOutput = `${this.colors.yellow}[tool]${this.colors.reset} ${this.colors.bold}${toolName}${this.colors.reset}\n`;
   169→        result.formattedOutput += `${this.colors.dim}  input: ${this.truncate(input, this.MAX_TOOL_INPUT_LENGTH)}${this.colors.reset}`;
   170→        break;
   171→      }
   172→
   173→      case 'tool_result': {
   174→        const isError = data.is_error;
   175→        const duration = this.toolStartTime ? this.formatDuration(Date.now() - this.toolStartTime) : '';
   176→        result.actions.push({ action: 'stop_spinner' });
   177→
   178→        if (isError) {
   179→          result.formattedOutput = `${this.colors.red}[error]${this.colors.reset} Tool failed ${duration ? `(${duration})` : ''}`;
   180→          if (data.content) {
   181→            result.formattedOutput += `\n${this.colors.red}  ${this.truncate(data.content, 300)}${this.colors.reset}`;
   182→          }
   183→        } else {
   184→          result.formattedOutput = `${this.colors.green}[done]${this.colors.reset} Tool completed ${duration ? `(${duration})` : ''}`;
   185→        }
   186→        break;
   187→      }
   188→
   189→      case 'error': {
   190→        const errorMsg = data.error?.message || data.message || 'Unknown error';
   191→        result.actions.push({ action: 'stop_spinner' });
   192→        result.formattedOutput = `${this.colors.red}[ERROR]${this.colors.reset} ${errorMsg}`;
   193→        break;
   194→      }
   195→
   196→      case 'message_start': {
   197→        const model = data.message?.model;
   198→        if (model) {
   199→          result.formattedOutput = `${this.colors.dim}[model: ${model}]${this.colors.reset}`;
   200→        }
   201→        result.actions.push({ action: 'set_message_start_time' });
   202→        break;
   203→      }
   204→
   205→      case 'message_stop': {
   206→        result.actions.push({ action: 'stop_spinner' });
   207→        result.formattedOutput = '';
   208→        break;
   209→      }
   210→
   211→      case 'message_delta': {
   212→        const usage = data.usage;
   213→        if (usage) {
   214→          const tokens = usage.output_tokens || 0;
   215→          result.formattedOutput = `${this.colors.dim}[tokens: ${tokens}]${this.colors.reset}`;
   216→        }
   217→        break;
   218→      }
   219→
   220→      case 'system': {
   221→        const text = data.message;
   222→        if (text) {
   223→          result.formattedOutput = `${this.colors.magenta}[system]${this.colors.reset} ${text}`;
   224→        }
   225→        break;
   226→      }
   227→
   228→      case 'result': {
   229→        const cost = data.cost_usd;
   230→        const duration = data.duration_ms;
   231→        const parts = [];
   232→        result.actions.push({ action: 'stop_spinner' });
   233→
   234→        if (cost) {
   235→          parts.push(`cost: $${cost}`);
   236→          result.actions.push({ action: 'add_cost', cost: parseFloat(cost) });
   237→        }
   238→        if (duration) {
   239→          parts.push(`duration: ${this.formatDuration(duration)}`);
   240→        }
   241→        if (parts.length > 0) {
   242→          result.formattedOutput = `${this.colors.dim}[stats] ${parts.join(', ')}${this.colors.reset}`;
   243→        }
   244→        break;
   245→      }
   246→
   247→      default: {
   248→        if (data.subagent) {
   249→          result.formattedOutput = `${this.colors.magenta}[subagent]${this.colors.reset} ${data.subagent}`;
   250→        }
   251→        break;
   252→      }
   253→    }
   254→
   255→    return result;
   256→  }
   257→}
