  if (unitTestsPassed && integrationPassed) {
    console.log('All tests passed! 🎉');
    process.exit(0);
  } else {
    console.log('Some tests failed! 💥');
    process.exit(1);
  }
}

if (require.main === module) {
  main().catch(console.error);
}

module.exports = { OutputFormatter, TestSuite };

